import React, { useState } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-green-50 to-blue-50 p-4">
            <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="w-full max-w-lg bg-white rounded-2xl shadow-xl overflow-hidden"
            >
                <div className="bg-gradient-to-r from-green-500 to-blue-600 p-6 text-white">
                    <motion.h2 
                        initial={{ y: -20 }}
                        animate={{ y: 0 }}
                        transition={{ duration: 0.5 }}
                        className="text-3xl font-bold text-center mb-6"
                    >
                        🌾 Crop Price Lookup
                    </motion.h2>
                    
                    <motion.div 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ duration: 0.5, delay: 0.2 }}
                        className="space-y-4"
                    >
                        <motion.div
                            whileHover={{ scale: 1.02 }}
                            transition={{ duration: 0.2 }}
                            className="relative"
                        >
                            <motion.select 
                                value={commodity} 
                                onChange={(e) => setCommodity(e.target.value)} 
                                className="w-full p-4 pl-4 pr-10 border-2 border-white/20 rounded-xl bg-white/10 backdrop-blur-sm text-white appearance-none focus:outline-none focus:ring-2 focus:ring-white/50 hover:bg-white/20 transition-all duration-300"
                            >
                                <option value="" className="text-gray-800">Select Commodity</option>
                                {commodityOptions.map((item, index) => (
                                    <option key={index} value={item} className="text-gray-800">{item}</option>
                                ))}
                            </motion.select>
                            <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none text-white">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
                                </svg>
                            </div>
                        </motion.div>

                        <motion.div
                            whileHover={{ scale: 1.02 }}
                            transition={{ duration: 0.2 }}
                            className="relative"
                        >
                            <motion.select 
                                value={district} 
                                onChange={(e) => setDistrict(e.target.value)} 
                                className="w-full p-4 pl-4 pr-10 border-2 border-white/20 rounded-xl bg-white/10 backdrop-blur-sm text-white appearance-none focus:outline-none focus:ring-2 focus:ring-white/50 hover:bg-white/20 transition-all duration-300"
                            >
                                <option value="" className="text-gray-800">Select District</option>
                                {districtOptions.map((item, index) => (
                                    <option key={index} value={item} className="text-gray-800">{item}</option>
                                ))}
                            </motion.select>
                            <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none text-white">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path>
                                </svg>
                            </div>
                        </motion.div>
                    </motion.div>
                    
                    <motion.button 
                        onClick={fetchPrices} 
                        whileHover={{ scale: 1.05, boxShadow: "0 8px 16px rgba(0,0,0,0.2)" }}
                        whileTap={{ scale: 0.95 }}
                        className="w-full mt-6 p-4 bg-white text-blue-600 font-bold rounded-xl shadow-lg hover:bg-blue-50 transition-all duration-300 flex items-center justify-center"
                    >
                        <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
                        </svg>
                        Get Prices
                    </motion.button>
                    
                    <AnimatePresence>
                        {loading && (
                            <motion.div 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                className="flex justify-center items-center mt-4"
                            >
                                <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-white"></div>
                            </motion.div>
                        )}
                        {error && (
                            <motion.p 
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0 }}
                                transition={{ duration: 0.3 }}
                                className="mt-4 text-red-200 text-center font-medium"
                            >
                                {error}
                            </motion.p>
                        )}
                    </AnimatePresence>
                </div>
                
                <AnimatePresence>
                    {prices && (
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            transition={{ duration: 0.4 }}
                            className="p-6"
                        >
                            <motion.h3 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ delay: 0.1 }}
                                className="text-2xl font-semibold text-gray-800 text-center mb-6"
                            >
                                Price Details
                            </motion.h3>
                            
                            <div className="grid gap-4">
                                {prices.map((data, index) => (
                                    <motion.div
                                        key={index}
                                        initial={{ opacity: 0, x: -20 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ delay: index * 0.1 }}
                                        whileHover={{ 
                                            scale: 1.02, 
                                            boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
                                            backgroundColor: "#f9fafb"
                                        }}
                                        className="p-5 border border-gray-200 rounded-xl bg-white shadow-md transition-all duration-300"
                                    >
                                        <div className="flex items-center mb-3">
                                            <span className="text-lg font-bold text-green-600 mr-2">Grade:</span>
                                            <span className="text-lg font-medium text-gray-800">{data.Grade}</span>
                                        </div>
                                        
                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                                            <motion.div 
                                                whileHover={{ scale: 1.05 }}
                                                className="p-3 bg-blue-50 rounded-lg"
                                            >
                                                <div className="text-sm text-blue-600 font-medium">Min Price</div>
                                                <div className="text-xl font-bold text-gray-800">₹ {data["Min Price"]}</div>
                                            </motion.div>
                                            
                                            <motion.div 
                                                whileHover={{ scale: 1.05 }}
                                                className="p-3 bg-green-50 rounded-lg"
                                            >
                                                <div className="text-sm text-green-600 font-medium">Modal Price</div>
                                                <div className="text-xl font-bold text-gray-800">₹ {data["Modal Price"]}</div>
                                            </motion.div>
                                            
                                            <motion.div 
                                                whileHover={{ scale: 1.05 }}
                                                className="p-3 bg-amber-50 rounded-lg"
                                            >
                                                <div className="text-sm text-amber-600 font-medium">Max Price</div>
                                                <div className="text-xl font-bold text-gray-800">₹ {data["Max Price"]}</div>
                                            </motion.div>
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </motion.div>
        </div>
    );
};

export default CropPriceLookup;
